public class PROTO_NC_OPTOOL_S2SCONNECT_LIST_ACK : IFiestaPacketBody
{
    public byte echo_data;
    public byte my_server_id;
    public ushort num_of_connections;
    public SERVER_CONN_INFO[] connection_info = [];

    public void Read(BinaryReader reader)
    {
        echo_data = reader.ReadByte();
        my_server_id = reader.ReadByte();
        num_of_connections = reader.ReadUInt16();
        connection_info = new SERVER_CONN_INFO[num_of_connections];
        for (int i = 0; i < num_of_connections; i++)
        {
            connection_info[i] = new SERVER_CONN_INFO();
            connection_info[i].Read(reader);
        }
    }

    public void Write(BinaryWriter writer)
    {
        writer.Write(echo_data);
        writer.Write(my_server_id);
        writer.Write(num_of_connections);
        for (int i = 0; i < connection_info.Length; i++)
            connection_info[i].Write(writer);
    }
}

